import React, { useState } from 'react';
import { submenus } from './submenus';
import { useNavigate, useLocation } from 'react-router-dom';

const itens = [
  { label: 'SCM', icon: '📡' },
  { label: 'TVpA', icon: '📺' },
  { label: 'STFC', icon: '☎️' },
  { label: 'RELATÓRIO ECONÔMICO', icon: '📊' },
  { label: 'INFRA', icon: '🏗️' },
  { label: 'POSTES', icon: '🪵' },
  { label: 'GERENCIADOR', icon: '👤' },
  { label: 'FINANCEIRO', icon: '💲' },
  { label: 'CONTRATOS E CERTIDÕES', icon: '📄' },
];

const MenuLateral = () => {
  const [submenuAberto, setSubmenuAberto] = useState(null);
  const navigate = useNavigate();

  const handleMouseEnter = (label) => {
    if (submenus[label]) setSubmenuAberto(label);
  };
  const handleMouseLeave = () => setSubmenuAberto(null);

  // Busca id do cliente selecionado na URL (query ou rota)
  const location = useLocation();
  const search = location.search;
  const params = new URLSearchParams(search);
  let idCliente = params.get('id');
  if (!idCliente) {
    // Tenta extrair da rota tipo /cliente/:id
    const match = location.pathname.match(/cliente\/(\d+)/);
    if (match) idCliente = match[1];
  }

  const handleSubmenuClick = (itemLabel, subLabel) => {
    if (itemLabel === 'SCM' && subLabel === 'Novo Relatório') {
      // Sempre tenta recuperar o idCliente do localStorage se não houver na URL
      let id = idCliente;
      if (!id) {
        try {
          const cliente = JSON.parse(localStorage.getItem('cliente_selecionado'));
          // Busca id em diferentes formatos
          if (cliente) {
            if (cliente.id) id = cliente.id;
            else if (cliente._id) id = cliente._id;
            else if (cliente.cliente && (cliente.cliente.id || cliente.cliente._id)) id = cliente.cliente.id || cliente.cliente._id;
          }
        } catch {}
      }
      if (id) {
        navigate(`/scm/cadastro?id=${id}`);
      } else {
        alert('Selecione um cliente antes de gerar o relatório SCM!');
      }
    } else if (itemLabel === 'TVpA' && subLabel === 'Novo Relatório') {
      navigate('/tvpa/cadastro');
    } else {
      alert(`Clicou em ${subLabel}`);
    }
  };

  return (
    <aside style={{
      width: 200,
      background: '#111',
      color: '#fff',
      minHeight: '100vh',
      position: 'fixed',
      left: 0,
      top: 0,
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      paddingTop: 24,
      zIndex: 10
    }}>
      <div style={{marginBottom: 32, textAlign: 'center'}}>
        <div style={{fontSize: 36, marginBottom: 8}}>👤</div>
        <div style={{fontWeight: 'bold', letterSpacing: 2}}>MENU</div>
      </div>
      <nav style={{width: '100%'}}>
        {itens.map(item => (
          <div
            key={item.label}
            style={{
              position: 'relative',
              display: 'flex',
              alignItems: 'center',
              gap: 12,
              padding: '12px 24px',
              cursor: 'pointer',
              color: item.label === 'RELATÓRIO ECONÔMICO' ? '#FFD600' : '#fff',
              fontWeight: item.label === 'RELATÓRIO ECONÔMICO' ? 'bold' : 'normal',
              fontSize: 16,
              transition: 'background 0.2s',
              background: submenuAberto === item.label ? '#222' : 'none',
            }}
            onMouseEnter={() => handleMouseEnter(item.label)}
            onMouseLeave={handleMouseLeave}
          >
            <span style={{fontSize: 20}}>{item.icon}</span>
            <span>{item.label}</span>
            {/* Submenu */}
            {submenuAberto === item.label && submenus[item.label] && (
              <div
                style={{
                  position: 'absolute',
                  left: '100%',
                  top: 0,
                  background: '#222',
                  color: '#fff',
                  minWidth: 180,
                  borderRadius: 8,
                  boxShadow: '2px 2px 8px #0003',
                  padding: '8px 0',
                  zIndex: 20,
                }}
                onMouseEnter={() => setSubmenuAberto(item.label)}
                onMouseLeave={handleMouseLeave}
              >
                {submenus[item.label].map(sub => (
                  <div
                    key={sub.label}
                    style={{
                      padding: '8px 20px',
                      cursor: 'pointer',
                      fontSize: 15,
                      whiteSpace: 'nowrap',
                      transition: 'background 0.2s',
                    }}
                    onClick={() => handleSubmenuClick(item.label, sub.label)}
                  >
                    {sub.label}
                  </div>
                ))}
              </div>
            )}
          </div>
        ))}
      </nav>
    </aside>
  );
};

export default MenuLateral;
